@namespace sv_989e92af5d9c422db4aa483431cd9b4f.Components.Pages.Settings
@using sv_989e92af5d9c422db4aa483431cd9b4f.Models

<div class="settings-section">
    <h4>Security</h4>
    <hr />

    <!-- Change Password Panel -->
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer;" @onclick="() => _passwordExpanded = !_passwordExpanded">
            <span>🔑 Change Password</span>
            <span>@(_passwordExpanded ? "▲" : "▼")</span>
        </div>
        @if (_passwordExpanded)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="_confirmPassword" />
                </div>

                @if (!string.IsNullOrEmpty(_passwordMessage))
                {
                    <div class="alert @(_passwordError ? "alert-danger" : "alert-success") py-2">
                        @_passwordMessage
                    </div>
                }

                <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @if (_changingPassword)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Update Password
                </button>

                @if (Settings.LastPasswordChange.HasValue)
                {
                    <small class="text-muted ms-3">
                        Last changed: @Settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                    </small>
                }
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <span class="badge @(Settings.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(Settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" checked="@Settings.TwoFactorEnabled" disabled
                       title="Contact admin to change 2FA settings" />
            </div>
        </div>
    </div>

    <!-- Active Sessions -->
    <div class="card mb-4">
        <div class="card-header">
            <h6 class="mb-0">Active Sessions</h6>
        </div>
        <div class="card-body p-0">
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead class="table-light">
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Settings.Sessions)
                        {
                            var isCurrent = session == Settings.Sessions.FirstOrDefault();
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-primary ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>
    </div>

    <!-- Revoke Confirmation Dialog -->
    @if (_sessionToRevoke is not null)
    {
        <div class="modal-backdrop fade show"></div>
        <div class="modal fade show d-block" tabindex="-1">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke this session?</p>
                        <p class="mb-0">
                            <strong>@_sessionToRevoke.Device</strong> — @_sessionToRevoke.Location
                        </p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                            @if (_revoking)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Revoke
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public SecuritySettings Settings { get; set; } = default!;
    [Parameter] public EventCallback<string> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool _passwordExpanded;
    private string _currentPassword = string.Empty;
    private string _newPassword = string.Empty;
    private string _confirmPassword = string.Empty;
    private string _passwordMessage = string.Empty;
    private bool _passwordError;
    private bool _changingPassword;

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private async Task ChangePasswordAsync()
    {
        _passwordMessage = string.Empty;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordMessage = "Current password is required.";
            _passwordError = true;
            return;
        }

        if (_newPassword.Length < 8)
        {
            _passwordMessage = "New password must be at least 8 characters.";
            _passwordError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordMessage = "New passwords do not match.";
            _passwordError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await OnChangePassword.InvokeAsync($"{_currentPassword}|{_newPassword}");
            _passwordMessage = "Password updated successfully!";
            _passwordError = false;
            _currentPassword = _newPassword = _confirmPassword = string.Empty;
        }
        catch (Exception ex)
        {
            _passwordMessage = $"Failed: {ex.Message}";
            _passwordError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        _sessionToRevoke = null;
        _revoking = false;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

