<div class="settings-section">
    <h4>Profile</h4>
    <hr />

    <div class="profile-avatar-area mb-4">
        <div class="avatar-preview">
            <img src="@AvatarUrl" alt="Avatar" class="rounded-circle" width="100" height="100" />
        </div>
        <div class="mt-2">
            <label class="form-label text-muted small">Avatar URL</label>
            <input type="text" class="form-control form-control-sm" value="@AvatarUrl"
                   @onchange="e => AvatarUrl = e.Value?.ToString() ?? string.Empty" />
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" @bind="DisplayName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="4" @bind="Bio"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = string.Empty"></button>
        </div>
    }

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = string.Empty;
    private string Email = string.Empty;
    private string AvatarUrl = string.Empty;
    private string Bio = string.Empty;

    private string _statusMessage = string.Empty;
    private bool _isError;
    private bool _saving;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        DisplayName = Profile.DisplayName;
        Email = Profile.Email;
        AvatarUrl = Profile.AvatarUrl;
        Bio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = string.Empty;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Profile saved successfully!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        LoadFromProfile();
        _statusMessage = string.Empty;
    }
}

