@namespace sv_989e92af5d9c422db4aa483431cd9b4f.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="sidebar-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_989e92af5d9c422db4aa483431cd9b4f.Components.Pages.Settings
@using sv_989e92af5d9c422db4aa483431cd9b4f.Models

<div class="settings-section">
    <h4>Notifications</h4>
    <hr />

    <div class="mb-4">
        <h6>General</h6>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" checked="@EmailNotifications"
                   @onchange="e => EmailNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" checked="@PushNotifications"
                   @onchange="e => PushNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" checked="@WeeklyDigest"
                   @onchange="e => WeeklyDigest = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h6>Muted Channels</h6>
        @foreach (var channel in AllChannels)
        {
            var isMuted = MutedChannels.Contains(channel);
            <div class="form-check mb-1">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">
                    #@channel @(isMuted ? "(muted)" : "")
                </label>
            </div>
        }
    </div>

    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = string.Empty"></button>
        </div>
    }

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }
    [Parameter] public List<string> AllChannels { get; set; } = [];

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];

    private string _statusMessage = string.Empty;
    private bool _saving;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = new List<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, new List<string>(MutedChannels));
        await OnSave.InvokeAsync(updated);
        _statusMessage = "Notification preferences saved!";
        _saving = false;
    }
}

