@namespace sv_989e92af5d9c422db4aa483431cd9b4f.Components.Pages.Settings
@using sv_989e92af5d9c422db4aa483431cd9b4f.Models

<div class="settings-section">
    <h4>Appearance</h4>
    <hr />

    <!-- Theme -->
    <div class="mb-4">
        <h6>Theme</h6>
        @foreach (var theme in new[] { "Light", "Dark", "System" })
        {
            <div class="form-check form-check-inline">
                <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                       value="@theme" checked="@(Theme == theme)"
                       @onchange="() => Theme = theme" />
                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
            </div>
        }
    </div>

    <!-- Font Size -->
    <div class="mb-4">
        <h6>Font Size</h6>
        @foreach (var size in new[] { "Small", "Medium", "Large" })
        {
            <div class="form-check form-check-inline">
                <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size}")"
                       value="@size" checked="@(FontSize == size)"
                       @onchange="() => FontSize = size" />
                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
            </div>
        }
    </div>

    <!-- Language -->
    <div class="mb-4">
        <h6>Language</h6>
        <select class="form-select" style="max-width: 250px;"
                value="@Language" @onchange="e => Language = e.Value?.ToString() ?? "English"">
            @foreach (var lang in Languages)
            {
                <option value="@lang" selected="@(lang == Language)">@lang</option>
            }
        </select>
    </div>

    <!-- Compact Mode -->
    <div class="mb-4">
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="compactMode"
                   checked="@CompactMode"
                   @onchange="e => CompactMode = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="compactMode">Compact Mode</label>
        </div>
    </div>

    <!-- Live Preview -->
    <div class="mb-4">
        <h6>Preview</h6>
        <div class="appearance-preview @PreviewThemeClass" style="@PreviewFontStyle">
            <div class="preview-header">
                <strong>Sample Header</strong>
            </div>
            <div class="preview-body" style="@(CompactMode ? "padding: 0.5rem;" : "padding: 1rem;")">
                <p class="mb-1">This is how your content will look with the selected settings.</p>
                <p class="mb-1 text-muted">Language: @Language</p>
                <div class="d-flex gap-2 mt-2">
                    <button class="btn btn-sm btn-primary">Action</button>
                    <button class="btn btn-sm btn-outline-secondary">Cancel</button>
                </div>
            </div>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = string.Empty"></button>
        </div>
    }

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save
    </button>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Settings { get; set; } = default!;
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
    private bool CompactMode;

    private string _statusMessage = string.Empty;
    private bool _saving;

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
        }
    }

    private string PreviewThemeClass => Theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewFontStyle => FontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
        await OnSave.InvokeAsync(updated);
        _statusMessage = "Appearance settings saved!";
        _saving = false;
    }
}

