@page "/settings"
@namespace sv_989e92af5d9c422db4aa483431cd9b4f.Components.Pages.Settings
@rendermode InteractiveServer
@using sv_989e92af5d9c422db4aa483431cd9b4f.Models
@using sv_989e92af5d9c422db4aa483431cd9b4f.Services

@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

@if (_loading)
{
    <div class="d-flex justify-content-center align-items-center" style="min-height: 400px;">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="settings-layout">
        <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="s => _activeSection = s" />

        <div class="settings-content">
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="@_profile!" OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@_notifications!" OnSave="SaveNotificationsAsync"
                                          AllChannels="@_allChannels" />
                    break;
                case "Security":
                    <SecuritySection Settings="@_security!" OnChangePassword="HandleChangePasswordAsync"
                                     OnRevokeSession="HandleRevokeSessionAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@_appearance!" OnSave="SaveAppearanceAsync" />
                    break;
            }
        </div>
    </div>
}

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notifications;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;
    private List<string> _allChannels = MockSettingsService.AllChannels;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllAsync();
        _loading = false;
    }

    private async Task LoadAllAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notifications = notifTask.Result;
        _security = securityTask.Result;
        _appearance = appearanceTask.Result;
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotificationsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notifications = prefs;
    }

    private async Task HandleChangePasswordAsync(string passwordData)
    {
        var parts = passwordData.Split('|', 2);
        await SettingsService.ChangePasswordAsync(parts[0], parts[1]);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleRevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
    }
}

/* Settings page layout */
.settings-layout {
    display: flex;
    gap: 0;
    min-height: calc(100vh - 120px);
    margin: -1rem -1.5rem;
}

/* Sidebar */
.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 500;
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* Content area */
.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    overflow-y: auto;
}

.settings-section h4 {
    margin-bottom: 0.25rem;
    font-weight: 600;
}

/* Avatar preview */
.avatar-preview {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.avatar-preview img {
    border: 3px solid #dee2e6;
    object-fit: cover;
}

/* Appearance preview */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    max-width: 400px;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    padding: 1rem;
}

/* Light theme preview */
.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background: #f8f9fa;
    border-color: #dee2e6;
}

/* Dark theme preview */
.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
}

.preview-dark .preview-header {
    background: #181825;
    border-color: #45475a;
    color: #cdd6f4;
}

.preview-dark .preview-body {
    color: #bac2de;
}

.preview-dark .text-muted {
    color: #7f849c !important;
}

/* System theme preview (gradient split) */
.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

.preview-system .preview-header {
    background: linear-gradient(135deg, #f8f9fa 50%, #181825 50%);
    border-color: #dee2e6;
}

